const raw = $input.first().json.choices?.[0]?.message?.content || '';
let data;
try {
  data = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch(e) {
  throw new Error('GPT-4o JSON invalide: ' + raw.slice(0, 200));
}
const confidence = data.confidence || 0;
return [{ json: {
  ...data,
  confidence,
  _source: 'pdf',
  _needs_review: confidence < 0.85,
  societe: $('Webhook AVA Dashboard').first().json.body?.societe || '',
  submitted_at: $('Webhook AVA Dashboard').first().json.body?.submitted_at || new Date().toISOString(),
} }];

const PCM = {
  'achats_marchandises': { debit: '6111', credit: '4411', tva: '3455', journal: 'ACH' },
  'ventes_produits':     { debit: '3421', credit: '7111', tva: '4455', journal: 'VTE' },
  'frais_transport':     { debit: '6142', credit: '4411', tva: '3455', journal: 'ACH' },
  'salaires':            { debit: '6171', credit: '4441', tva: null,   journal: 'OD'  },
  'services':            { debit: '6131', credit: '4411', tva: '3455', journal: 'ACH' },
  'frais_deplacement':   { debit: '6185', credit: '5141', tva: '3455', journal: 'OD'  },
  'autres':              { debit: '6199', credit: '4411', tva: '3455', journal: 'ACH' },
};
const item = $input.first().json;
const rule = PCM[item.category] || PCM['autres'];
const vat_amount = Math.round(item.amount_ht * item.vat_rate * 100) / 100;
const lines = [
  { compte: rule.debit, debit: item.amount_ht, credit: 0, libelle: item.vendor },
];
if (rule.tva) lines.push({ compte: rule.tva, debit: vat_amount, credit: 0, libelle: 'TVA déductible' });
lines.push({ compte: rule.credit, debit: 0, credit: item.amount_ttc, libelle: item.vendor });
const totalDebit  = lines.reduce((s,l) => s + l.debit, 0);
const totalCredit = lines.reduce((s,l) => s + l.credit, 0);
if (Math.abs(totalDebit - totalCredit) > 0.01) throw new Error(`Non équilibrée: D=${totalDebit} C=${totalCredit}`);
return [{ json: { ...item, pcm_lines: lines, journal_code: rule.journal, debit_account: rule.debit, credit_account: rule.credit } }];

const d = $input.first().json;
// Build CSV row
const headers = ['N° Facture','Date','Tiers','Société','Type','Montant HT','TVA','Montant TTC','Taux TVA','Catégorie PCM','Journal PCM','Compte Débit','Compte Crédit','Source','Confiance IA','Soumis le','Statut'];
const escape = v => '"' + String(v ?? '').replace(/"/g, '""') + '"';
const row = [
  d.invoice_number,
  d.date,
  d.vendor,
  d.societe,
  d.type,
  d.amount_ht,
  d.amount_tva,
  d.amount_ttc,
  (d.vat_rate * 100) + '%',
  d.category,
  d.journal_code,
  d.debit_account,
  d.credit_account,
  d._source,
  d.confidence,
  d.submitted_at,
  'Traité'
].map(escape).join(',');
const csv = headers.map(escape).join(',') + '\n' + row;
return [{ json: { ...d, csv_row: csv, csv_filename: 'AVA_' + (d.invoice_number || 'facture').replace(/[^a-zA-Z0-9]/g,'_') + '_' + new Date().toISOString().slice(0,10) + '.csv' } }];

const item = $input.first().json;
return [{ json: {
  alert: 'LOW_CONFIDENCE',
  invoice_number: item.invoice_number,
  vendor: item.vendor,
  confidence: item.confidence,
  source: item._source,
  message: `⚠️ ${item.invoice_number} (${item.vendor}) — confiance ${Math.round(item.confidence*100)}% — révision requise`,
} }];
